const fullText = $input.all()[0].json.text;

const chunkSize = 700000;
const overlapSize = 50000;
const chunks = [];
let chunkIndex = 0;

function findSafeBoundary(text, position) {
  const paragraphBreak = text.lastIndexOf('\n\n', position);
  if (paragraphBreak > position - 5000 && paragraphBreak !== -1) {
    return paragraphBreak + 2;
  }

  const sentenceEndings = ['. ', '.\n', '! ', '!\n', '? ', '?\n'];
  let bestBoundary = -1;

  for (const ending of sentenceEndings) {
    const pos = text.lastIndexOf(ending, position);
    if (pos > bestBoundary && pos > position - 5000) {
      bestBoundary = pos + ending.length;
    }
  }

  if (bestBoundary === -1) {
    bestBoundary = text.lastIndexOf(' ', position);
  }

  return bestBoundary !== -1 ? bestBoundary : position;
}

for (let i = 0; i < fullText.length; i += (chunkSize - overlapSize)) {
  let endPos = Math.min(i + chunkSize, fullText.length);

  if (endPos < fullText.length) {
    endPos = findSafeBoundary(fullText, endPos);
  }

  const chunkText = fullText.substring(i, endPos);

  chunks.push({
    json: {
      chunkText: chunkText,
      chunkIndex: chunkIndex,
      totalChunks: 0,  // Initialize as 0 instead of null
      isFirstChunk: chunkIndex === 0,
      isLastChunk: false
    }
  });

  chunkIndex++;
  if (endPos >= fullText.length) break;
}

// Update metadata
chunks.forEach((chunk, idx) => {
  chunk.json.totalChunks = chunks.length;
  chunk.json.isLastChunk = (idx === chunks.length - 1);
});

return chunks;

// Collect all chunk results
const allResults = $input.all();

// Combine them into one item for Message Model 2
return [{
  json: {
    chunkResults: allResults.map((item, idx) => ({
      chunkIndex: idx,
      result: item.json
    })),
    totalChunks: allResults.length,
    originalPrompt: $node["Webhook"].json.body.prompt
  }
}];
